        return 'claude --dangerously-skip-permissions';
      case 'custom':
        return this.config.get<string>(
          CONFIG_KEYS.claudeCodeCommand.replace('gofer.', ''),
          DEFAULTS.claudeCodeCommand
        );
      case 'standard':
      default:
        return 'claude';
    }
  }

  /**
