 */
export function getWorkspacePaths(workspacePath: string) {
  const path = require('path');

  return {
    specify: path.join(workspacePath, SPECIFY_FOLDER),
    specs: path.join(workspacePath, SPECIFY_FOLDER, SPECS_FOLDER),
