  private formatTokens(tokens: number): string {
    if (tokens >= 1000) {
      return `${(tokens / 1000).toFixed(1)}k`;
    }
    return tokens.toString();
  }

  private getHealthColor(utilization: number): string {
    if (utilization > 70) return 'charts.red';
